function choose<T>(values: T[], random: () => number): T {
  if (!values.length) {
    throw new Error("Cannot choose from an empty array");
  }
  return values[Math.floor(random() * values.length)];
}

function clause(input: string): string {
  return input.trim().replace(/[.!?]+$/g, "");
}

function sentence(input: string): string {
  const trimmed = input.trim();
  if (!trimmed) return "";
  const capitalized = `${trimmed[0].toUpperCase()}${trimmed.slice(1)}`;
  return /[.!?]$/.test(capitalized) ? capitalized : `${capitalized}.`;
}

function lowerFirst(input: string): string {
  if (!input) return input;
  return input[0].toLowerCase() + input.slice(1);
}

const PART_OF_SYNONYMS = [
  "the part of",
  "the aspect of",
  "the layer of",
  "the side of",
  "the element of",
  "the face of",
  "the thread of",
  "the territory of",
];

function varyPartOf(text: string, random: () => number): string {
  if (!text.includes("the part of")) return text;
  const replacement = choose(PART_OF_SYNONYMS, random);
  return replacement === "the part of" ? text : text.replace(/\bthe part of\b/g, replacement);
}

const YOUR_OWN_ALTERNATIVES = [
  "your own",
  "your own",
  "your own",
  "your particular",
  "your actual",
];

function varyYourOwn(text: string, random: () => number): string {
  if (!text.includes("your own")) return text;
  const replacement = choose(YOUR_OWN_ALTERNATIVES, random);
  if (replacement === "your own") return text;
  // Only replace the first occurrence to avoid over-substitution
  return text.replace(/\byour own\b/, replacement);
}

function sortedPairKey(a: number, b: number): string {
  return a < b ? `${a}-${b}` : `${b}-${a}`;
}

