function chooseAvoiding(
  pool: string[],
  id: number,
  usedMap: Map<number, Set<string>>,
  random: () => number,
): string {
  if (pool.length <= 1) return pool[0] ?? "";
  const used = usedMap.get(id);
  const available = used ? pool.filter((p) => !used.has(p)) : pool;
  const chosen = choose(available.length > 0 ? available : pool, random);
  if (!usedMap.has(id)) usedMap.set(id, new Set());
  usedMap.get(id)!.add(chosen);
  return chosen;
}

export function buildCardAssociationPhrase(
  input: number | CardMeaning,
  subjectId: SubjectId,
  domain: Domain,
  random: () => number,
  context?: ReadingContext,
): string {
  const card = cardFrom(input);
  const subjectPool = SUBJECT_CARD_ASSOCIATION_NOTES[subjectId]?.[card.id] ?? [];
  if (subjectPool.length) {
    const picked = context
      ? chooseAvoiding(subjectPool, card.id, context.usedCardPhrases, random)
      : choose(subjectPool, random);
    return varyYourOwn(varyPartOf(picked, random), random);
  }

  const specialPool = CARD_ASSOCIATION_NOTES[card.id]?.[domain] ?? CARD_ASSOCIATION_NOTES[card.id]?.general ?? [];
  if (specialPool.length) {
    const picked = context
      ? chooseAvoiding(specialPool, card.id, context.usedCardPhrases, random)
      : choose(specialPool, random);
    return varyYourOwn(varyPartOf(picked, random), random);
  }

  const domainLine = clause(card.domainVariants[domain]);
  const keywords = naturalJoin(card.keywords.slice(0, 3));
  const action = clause(card.action);

  return compactAssociationPhrase(
    choose(
      [
        `${domainLine}, with ${keywords} close to the surface`,
        `the ${keywords} layer of the situation, especially where ${domainLine}`,
        `${domainLine}, especially where ${keywords} have been building quietly`,
        `${domainLine}, and the need to ${action}`,
      ],
      random,
    ),
  );
}

export function buildHouseAssociationPhrase(
  input: number | HouseMeaning,
  subjectId: SubjectId,
  domain: Domain,
  random: () => number,
  context?: ReadingContext,
): string {
  const house = houseFrom(input);
  const subjectPool = SUBJECT_HOUSE_ASSOCIATION_NOTES[subjectId]?.[house.id] ?? [];
  if (subjectPool.length) {
    const picked = context
      ? chooseAvoiding(subjectPool, house.id, context.usedHousePhrases, random)
      : choose(subjectPool, random);
    return varyYourOwn(varyPartOf(picked, random), random);
  }

  const specialPool = HOUSE_ASSOCIATION_NOTES[house.id]?.[domain] ?? HOUSE_ASSOCIATION_NOTES[house.id]?.general ?? [];
  if (specialPool.length) {
    const picked = context
      ? chooseAvoiding(specialPool, house.id, context.usedHousePhrases, random)
      : choose(specialPool, random);
    return varyYourOwn(varyPartOf(picked, random), random);
  }

  return compactAssociationPhrase(
    choose(
      [
        `${house.shortFocus} and the part of the field where ${houseDescriptionPhrase(house)}`,
        `the part of the field where ${houseDescriptionPhrase(house)}`,
        `the layer of the situation where ${houseDescriptionPhrase(house)}`,
      ],
      random,
    ),
  );
}

export function buildCardAssociationSentence(
  input: number | CardMeaning,
  subjectId: SubjectId,
  domain: Domain,
  random: () => number,
): string {
  const card = cardFrom(input);
  const phrase = buildCardAssociationPhrase(card, subjectId, domain, random);
  const scope = SUBJECT_SCOPE[subjectId];

  return sentence(
    choose(
      [
        `${card.name} often points to ${phrase} in ${scope}`,
        `${card.name} colors ${scope} through ${phrase}`,
        `Here, ${card.name} emphasizes ${phrase}`,
        `In ${scope}, ${card.name} keeps returning to ${phrase}`,
        `${card.name} tends to draw ${scope} toward ${phrase}`,
        `When ${card.name} appears here, it pulls ${scope} toward ${phrase}`,
        `${card.name} carries ${phrase} into the reading's picture of ${scope}`,
        `${card.name} shifts the tone of ${scope} toward ${phrase}`,
      ],
      random,
    ),
  );
}

export function buildPositionedCardAssociationSentence(
  input: number | CardMeaning,
  position: CardNarrativePosition,
  subjectId: SubjectId,
  domain: Domain,
  random: () => number,
): string {
  const card = cardFrom(input);
  const pool = CARD_POSITION_ASSOCIATION_NOTES[card.id]?.[position];
  if (!pool?.length) {
    return buildCardAssociationSentence(card, subjectId, domain, random);
  }

  const phrase = choose(pool, random);

  if (position === "situation") {
    return sentence(
      choose(
        [
          `${card.name} names the opening condition: ${phrase}`,
          `${card.name} gives the beginning its shape through ${phrase}`,
          `${card.name} starts the sequence by pointing to ${phrase}`,
          `${card.name} sets the first terms of the reading: ${phrase}`,
        ],
        random,
      ),
    );
  }

  if (position === "pivot") {
    return sentence(
      choose(
      [
        `${card.name} makes the pivot about ${phrase}`,
        `${card.name} becomes the hinge here because it names ${phrase}`,
        `The middle card asks for attention to ${phrase}`,
        `${card.name} brings this into the center of the sequence: ${phrase}`,
      ],
      random,
    ),
    );
  }

  return sentence(
    choose(
      [
        `For the next step, ${card.name} emphasizes ${phrase}`,
        `${card.name} gives the way forward its shape through ${phrase}`,
        `The advice line becomes more concrete through ${phrase}`,
        `Looking ahead, ${card.name} turns attention toward ${phrase}`,
      ],
      random,
    ),
  );
}

export function buildHouseAssociationSentence(
  input: number | HouseMeaning,
  subjectId: SubjectId,
  domain: Domain,
  random: () => number,
): string {
  const house = houseFrom(input);
  const houseName = displayHouseName(house);
  const housePhrase = buildHouseAssociationPhrase(house, subjectId, domain, random);
  const housePhraseObject = housePhrase.replace(/^where\s+/i, "the place where ");
  const housePhraseNoWhere = housePhrase.replace(/^where\s+/i, "");

  return sentence(
    choose(
      [
        `${houseName} keeps drawing attention to ${housePhraseObject}`,
        `${houseName} makes ${housePhraseObject} harder to ignore`,
        `In ${houseName}, the emphasis falls on ${housePhraseObject}`,
        `${houseName} is where ${housePhraseNoWhere} becomes most concrete`,
        `Whatever else is happening, ${houseName} keeps pulling focus back to ${housePhraseObject}`,
        `The weight of ${houseName} lands on ${housePhraseObject}, and other readings nearby are shaped by it`,
        `${houseName} grounds the reading in ${housePhraseObject}`,
        `${houseName} localizes the pressure around ${housePhraseObject}`,
      ],
      random,
    ),
  );
}

export function buildOverlayAssociationSentence(input: {
  card: number | CardMeaning;
  house: number | HouseMeaning;
  subjectId: SubjectId;
  domain: Domain;
  random: () => number;
}): string {
  const card = cardFrom(input.card);
  const house = houseFrom(input.house);
  const houseName = displayHouseName(house);
  const overlayOverride = SUBJECT_OVERLAY_ASSOCIATION_NOTES[input.subjectId]?.[sortedPairKey(card.id, house.id)];
  if (overlayOverride?.length) {
    const overlayPhrase = varyPartOf(choose(overlayOverride, input.random), input.random);
    return sentence(
      choose(
        [
          `${card.name} in ${houseName} brings ${overlayPhrase}`,
          `In ${houseName}, ${card.name} points to ${overlayPhrase}`,
          `${card.name} meeting ${houseName} suggests ${overlayPhrase}`,
        ],
        input.random,
      ),
    );
  }

  const housePhrase = compactAssociationPhrase(
    buildHouseAssociationPhrase(house, input.subjectId, input.domain, input.random),
  );
  const cardPhrase = compactAssociationPhrase(
    buildCardAssociationPhrase(card, input.subjectId, input.domain, input.random),
  );
  // Strip leading words that would cause double-word collisions in specific templates
  const cardPhraseNoHow = cardPhrase.replace(/^how\s+/i, "");
  const housePhraseNoWhere = housePhrase.replace(/^where\s+/i, "");

  return sentence(
    choose(
      [
        `${card.name} in ${houseName} ties ${cardPhrase} to ${housePhrase}`,
        `${houseName} frames ${card.name} through ${housePhrase}, making ${cardPhrase} harder to ignore`,
        `Placed in ${houseName}, ${card.name} shows how ${cardPhraseNoHow} is being shaped by ${housePhrase}`,
        `${card.name} meeting ${houseName} brings ${cardPhrase} into the atmosphere of ${housePhrase}`,
        `${card.name} landing in ${houseName} means ${cardPhrase} is now working inside the conditions of ${housePhrase}`,
        `The combination of ${card.name} and ${houseName} concentrates the reading: ${cardPhrase} is where ${housePhraseNoWhere} becomes personal`,
        `In ${houseName}, ${card.name} cannot avoid ${housePhrase} — and the result is that ${cardPhrase} takes on a sharper, more grounded quality`,
        `${houseName} gives ${card.name} a specific place to act: ${cardPhrase} has to answer the conditions of ${housePhrase}`,
        `${card.name} does not stay abstract in ${houseName}; it becomes visible through ${housePhrase}`,
        `Read through ${houseName}, ${card.name} turns ${cardPhrase} into something that has to be handled where ${housePhraseNoWhere}`,
        `${houseName} changes the scale of ${card.name}, moving ${cardPhrase} from a general signal into the territory of ${housePhrase}`,
        `${card.name} in ${houseName} shows the point where ${cardPhrase} meets the practical reality of ${housePhrase}`,
      ],
      input.random,
    ),
  );
}

export function buildPairAssociationSentence(input: {
  cardA: number | CardMeaning;
  cardB: number | CardMeaning;
  subjectId: SubjectId;
  domain: Domain;
  random: () => number;
}): string {
  const cardA = cardFrom(input.cardA);
  const cardB = cardFrom(input.cardB);
  const pairOverride = SUBJECT_PAIR_ASSOCIATION_OVERRIDES[input.subjectId]?.[sortedPairKey(cardA.id, cardB.id)];
  if (pairOverride?.length) {
    const PAIR_OPENERS = [
      "This pairing says",
      "Together, these cards say",
      "The combination says",
      "These two cards say",
      "Read together, they say",
    ];
    const raw = varyPartOf(choose(pairOverride, input.random), input.random);
    const stripped = raw.replace(/^This pairing says\s+/i, "");
    const opener = choose(PAIR_OPENERS, input.random);
    return sentence(`${opener} ${lowerFirst(stripped)}`);
  }
  const batchCardCandidate = [cardA, cardB].find((card) => BATCH_PAIR_ASSOCIATION_NOTES[card.id]);
  if (batchCardCandidate) {
    const batchCard = batchCardCandidate;
    const otherCard = batchCard.id === cardA.id ? cardB : cardA;
    const batchPairNotes = BATCH_PAIR_ASSOCIATION_NOTES[batchCard.id]!;
    if (SUPPORTIVE_PAIR_CARD_IDS.has(otherCard.id)) {
      return sentence(
        choose(
          [
            `${batchCard.name} with ${otherCard.name} shows support in motion: ${choose(batchPairNotes.supportive, input.random)}`,
            `${batchCard.name} and ${otherCard.name} work supportively here: ${choose(batchPairNotes.supportive, input.random)}`,
            `The helpful side of this pairing is specific: ${choose(batchPairNotes.supportive, input.random)}`,
            `${otherCard.name} strengthens ${batchCard.name} here, suggesting ${choose(batchPairNotes.supportive, input.random)}`,
          ],
          input.random,
        ),
      );
    }

    if (PRESSURE_PAIR_CARD_IDS.has(otherCard.id)) {
      return sentence(
        choose(
          [
            `${batchCard.name} with ${otherCard.name} names a pressure point: ${choose(batchPairNotes.pressure, input.random)}`,
            `${batchCard.name} and ${otherCard.name} work as a pressure pair here: ${choose(batchPairNotes.pressure, input.random)}`,
            `The harder side of this pairing is specific: ${choose(batchPairNotes.pressure, input.random)}`,
            `${otherCard.name} puts pressure on ${batchCard.name} here, suggesting ${choose(batchPairNotes.pressure, input.random)}`,
          ],
          input.random,
        ),
      );
    }
  }

  const leftKeywords = normalizePairKeywords(naturalJoin(cardA.keywords.slice(0, 2)).toLowerCase());
  const rightKeywords = normalizePairKeywords(naturalJoin(cardB.keywords.slice(0, 2)).toLowerCase());
  // Avoid "X and Y and A and B" chains when each side already contains "and"
  const kwJoin = (left: string, right: string): string =>
    left.includes(" and ") || right.includes(" and ")
      ? `${left} alongside ${right}`
      : `${left} and ${right}`;

  return sentence(
    choose(
      [
        `${cardA.name} and ${cardB.name} show ${kwJoin(leftKeywords, rightKeywords)} actively shaping each other rather than sitting in separate lanes`,
        `Taken together, ${cardA.name} and ${cardB.name} make ${kwJoin(leftKeywords, rightKeywords)} part of the same living dynamic`,
        `${cardA.name} and ${cardB.name} place ${kwJoin(leftKeywords, rightKeywords)} in the same frame — and make each harder to ignore`,
        `${cardA.name} and ${cardB.name} show ${leftKeywords} working through ${rightKeywords}, which is why the reading cannot treat them as separate issues`,
        `${cardA.name} alongside ${cardB.name} means ${kwJoin(leftKeywords, rightKeywords)} are not separate threads — they are already interacting`,
        `The combination of ${cardA.name} and ${cardB.name} makes ${kwJoin(leftKeywords, rightKeywords)} part of the same question`,
        `${cardA.name} and ${cardB.name} together pull ${kwJoin(leftKeywords, rightKeywords)} into the same orbit`,
        `What ${cardA.name} starts with ${leftKeywords}, ${cardB.name} reshapes through ${rightKeywords} — the two cards speak as one voice here`,
        `${cardA.name} and ${cardB.name} are not background noise: ${kwJoin(leftKeywords, rightKeywords)} is the mechanism the reading is describing`,
        `Neither ${cardA.name} nor ${cardB.name} can be understood alone in this spread — ${kwJoin(leftKeywords, rightKeywords)} describes a single dynamic, not two separate ones`,
        `${cardA.name} gives the reading ${leftKeywords}; ${cardB.name} answers with ${rightKeywords}, so the meaning sits in their exchange`,
        `${cardA.name} and ${cardB.name} form a working pair here: ${kwJoin(leftKeywords, rightKeywords)} keep modifying one another`,
        `${cardA.name} sets up ${leftKeywords}, but ${cardB.name} decides how that pressure moves through ${rightKeywords}`,
        `${cardB.name} changes the reading of ${cardA.name}: ${rightKeywords} becomes the condition that ${leftKeywords} has to answer`,
        `The useful question is not ${cardA.name} or ${cardB.name} separately, but how the first signal changes once the layer of ${rightKeywords} enters the picture`,
        `${cardA.name} supplies the first signal, ${cardB.name} supplies the consequence, and together they make ${kwJoin(leftKeywords, rightKeywords)} actionable`,
      ],
      input.random,
    ),
  );
}

export function buildActionDirectiveSentence(input: {
  actionCard: number | CardMeaning;
  house: number | HouseMeaning;
  subjectId: SubjectId;
  domain: Domain;
  random: () => number;
}): string {
  const card = cardFrom(input.actionCard);
  const house = houseFrom(input.house);
  const houseName = displayHouseName(house);
  const action = clause(card.action);
  const housePhrase = compactAssociationPhrase(
    buildHouseAssociationPhrase(house, input.subjectId, input.domain, input.random),
  );
  const cardPhrase = compactAssociationPhrase(
    buildCardAssociationPhrase(card, input.subjectId, input.domain, input.random),
  );
  const actionSentence = varyYourOwn(
    varyPartOf(
      SUBJECT_HOUSE_ACTION_OVERRIDES[input.subjectId]?.[house.id]?.length
        ? choose(SUBJECT_HOUSE_ACTION_OVERRIDES[input.subjectId]?.[house.id] ?? [], input.random)
        : naturalizeAction(action),
      input.random,
    ),
    input.random,
  );
  const fieldWhereMatch = housePhrase.match(/the part of the field where (.+)$/i);
  const wherePhrase = fieldWhereMatch?.[1] ?? null;
  const THIS_IS_WHERE_OPENERS = [
    "This is where",
    "Here is where",
    "This is the point where",
    "This is the moment where",
  ];
  const followThroughOverrides = SUBJECT_HOUSE_FOLLOW_THROUGH_OVERRIDES[input.subjectId]?.[house.id] ?? [];
  const hasFollowThroughOverride = followThroughOverrides.length > 0;
  const isCardEqualsHouse = card.id === house.id;
  const followThroughSentence = hasFollowThroughOverride
    ? (() => {
        const raw = choose(followThroughOverrides, input.random);
        const stripped = raw.replace(/^This is where\s+/i, "");
        const opener = choose(THIS_IS_WHERE_OPENERS, input.random);
        return `${opener} ${lowerFirst(stripped)}`;
      })()
    : isCardEqualsHouse && OWN_HOUSE_FOLLOW_THROUGH[card.id]?.length
        ? choose(OWN_HOUSE_FOLLOW_THROUGH[card.id] ?? [], input.random)
    : isCardEqualsHouse
      ? choose(
          [
            `${card.name} in ${houseName} makes this one of the clearest points in the spread`,
            `${card.name} matching its own house concentrates the signal unusually`,
            `Because ${card.name} and ${houseName} point to the same place, this is worth trusting`,
            `What ${card.name} and ${houseName} share here makes the signal unusually direct`,
            `${card.name} landing in its own house gives the reading a plain statement`,
            `${card.name} matching ${houseName} removes ambiguity from this part of the spread`,
            `When ${card.name} and ${houseName} are one, the reading needs response more than decoding`,
            `${card.name} in its own house does not hedge; the message is unusually direct`,
            `The coincidence of ${card.name} and ${houseName} collapses the usual ambiguity into a single instruction`,
            `This is one of the cleaner signals a spread can offer: ${card.name} and house speaking the same language`,
            `${card.name} matching its house means the reading has already done much of the interpretive work`,
            `The ${card.name} signal does not need much decoding here; it is as plain as the spread gets`,
          ],
          input.random,
        )
      : wherePhrase
        ? `${choose(THIS_IS_WHERE_OPENERS, input.random)} ${wherePhrase}`
        : choose(
            [
              `That keeps the focus on ${housePhrase}`,
              `The reading's weight gathers at ${housePhrase} — and that is where the thread leads`,
              `That is where acting first would carry the most weight`,
              `That is where the reading's weight concentrates most`,
              `The clearest directive in this spread runs through ${housePhrase}`,
              `Everything else in the reading orbits this — ${housePhrase} is where the leverage sits`,
              `If you only act on one thing from this reading, this is where it counts`,
              `${housePhrase} is the part of this spread that is asking for something concrete`,
              `The reading does not leave much ambiguity about where the weight falls — ${housePhrase} carries it`,
            ],
            input.random,
          );

  return sentence(
    choose(
      hasFollowThroughOverride
        ? [
            `If anything deserves closer attention here, it is ${houseName}: ${actionSentence}. ${followThroughSentence}`,
            `The thread worth following runs through ${houseName}: ${actionSentence}. ${followThroughSentence}`,
            `The reading concentrates most clearly at ${houseName}: ${actionSentence}. ${followThroughSentence}`,
            `${houseName} is where the weight lands: ${actionSentence}. ${followThroughSentence}`,
            `The clearest signal in this spread sits at ${houseName}: ${actionSentence}. ${followThroughSentence}`,
            `Among everything here, ${houseName} asks for the most direct response: ${actionSentence}. ${followThroughSentence}`,
          ]
        : [
            `The place most worth returning to is ${houseName}: ${actionSentence}. ${followThroughSentence}`,
            `${houseName} is where the reading keeps pointing: ${actionSentence}. ${followThroughSentence}`,
            `The most actionable signal in this spread sits at ${houseName}: ${actionSentence}. ${followThroughSentence}`,
            `When the reading is asked where the weight falls, it points to ${houseName}: ${actionSentence}. ${followThroughSentence}`,
            `The reading's clearest practical signal is at ${houseName}: ${actionSentence}. ${followThroughSentence}`,
            `The weight in this spread gathers at ${houseName}: ${actionSentence}. ${followThroughSentence}`,
          ],
      input.random,
    ),
  );
}
